SELECT id, name, create_time, update_time
FROM category
WHERE name = #{name}

SELECT COUNT(*)
FROM problem_category
WHERE category_id = #{categoryId}

SELECT COUNT(*) FROM problem p
AND p.difficulty = #{difficulty}
AND (p.title LIKE CONCAT('%', #{keyword}, '%') OR p.description LIKE CONCAT('%', #{keyword}, '%'))
AND EXISTS ( SELECT 1 FROM problem_category pc2 JOIN category c2 ON pc2.category_id = c2.id WHERE pc2.problem_id = p.id AND c2.name IN
#{name}
)

SELECT p.id, p.title, p.difficulty, p.pass_rate
FROM problem p


        AND p.difficulty = #{difficulty}


        AND (p.title LIKE CONCAT('%', #{keyword}, '%') OR p.description LIKE CONCAT('%', #{keyword}, '%'))


        AND EXISTS (
            SELECT 1 FROM problem_category pc2
            JOIN category c2 ON pc2.category_id = c2.id
            WHERE pc2.problem_id = p.id
            AND c2.name IN

                #{name}

        )


ORDER BY p.id
LIMIT #{offset}, #{size}

